/**
 * Emits docs/corporate/suite/brand-tokens.json from brand.js (single source of truth).
 * Run: npm run brand:tokens (from 04_SOFTWARE/p31-forge)
 */
const fs = require("fs");
const path = require("path");
const { COLORS, TYPE, ENTITY, SOCIAL, PAGES } = require("../brand.js");

const out = path.join(__dirname, "../../../docs/corporate/suite/brand-tokens.json");
const asHex = (c) => (c && c.length === 6 ? `#${c}` : c);

const payload = {
  $schema: "https://p31ca.org/none",
  description:
    "Generated by 04_SOFTWARE/p31-forge: npm run brand:tokens. Do not hand-edit; edit brand.js and re-run.",
  version: "1.0.0",
  source: "04_SOFTWARE/p31-forge/brand.js",
  colors: {
    coral: asHex(COLORS.coral),
    coralDark: asHex(COLORS.coralDark),
    teal: asHex(COLORS.teal),
    black: asHex(COLORS.black),
    dark: asHex(COLORS.dark),
    med: asHex(COLORS.med),
    gray: asHex(COLORS.gray),
    lightGray: asHex(COLORS.lightGray),
    border: asHex(COLORS.border),
    rule: asHex(COLORS.rule),
    subtle: asHex(COLORS.subtle),
    warmBg: asHex(COLORS.warmBg),
    lightBg: asHex(COLORS.lightBg),
    alertBg: asHex(COLORS.alertBg),
    white: asHex(COLORS.white),
  },
  typography: {
    serif: "Georgia, 'Times New Roman', serif",
    mono: "'JetBrains Mono', 'Consolas', monospace",
    halfPoints: TYPE,
  },
  pages: PAGES,
  entity: {
    org: ENTITY.org,
    ein: ENTITY.ein,
    einDate: ENTITY.einDate,
    incDate: ENTITY.incDate,
    entityType: ENTITY.entityType,
    website: ENTITY.website,
    appSite: ENTITY.appSite,
    github: ENTITY.github,
    orcid: ENTITY.orcid,
  },
  social: {
    hashtags: SOCIAL.hashtags,
    tagline: SOCIAL.tagline,
  },
};

fs.mkdirSync(path.dirname(out), { recursive: true });
fs.writeFileSync(out, JSON.stringify(payload, null, 2) + "\n", "utf8");
console.log("Wrote", out);
